input.command:
cd /workspace/data; echo "=== features ==="; cut -f3 dje.trn | sort | uniq -c; echo "=== check transformations ==="; awk -F'\t' '{
  feat=$3; lemma=$1; form=$2;
  if(form==lemma) t="IDENT";
  else if(form=="na"lemma) t="na-prefix";
  else if(form=="ga"lemma) t="ga-prefix";
  else t="OTHER";
  print feat, t
}' dje.trn | sort | uniq -c
